#include <bits/stdc++.h>using namespace std; int main(){    int n, t;    cin >> n >> t;    vector<int> v(n);    for(int i = 0; i < n; i++){        cin >> v[i];    }     int l = 0, sum = 0, ans = 0;    for(int r = 0; r < n; r++){        sum += v[r];        while(sum > t){            sum -= v[l];            l++;        }        ans = max(ans, r - l + 1);    }     cout << ans;    return 0;}